  const topbarSectionOptions = [
    ...mainTabs,
    { key: "settings", label: "Settings", target: "menu" },
  ];
  const topbarSectionValue = activeTab === "menu" ? "settings" : activeMainTab || "home";
  const showAppMessage = (message) => {
    setVaultToast(String(message || "Something went wrong."));
    return false;
  };
  const compactInventorySaveFailure = (failures = []) => {
    const uniqueFailures = [...new Set(
      failures
        .map((failure) => typeof failure === "string" ? failure : `${failure?.itemName || "Inventory item"} failed: ${failure?.error || "Could not save"}`)
        .filter(Boolean)
    )];
    if (uniqueFailures.length) console.error("Inventory save failures", uniqueFailures);
    return "Could not save item.";
  };
  const blockGuestSave = () => {
    if (!guestPreviewActive) return false;
    setVaultToast("Create a free account to save this.");
    return true;
  };
  const activeWorkspace = useMemo(
    () => workspaces.find((workspace) => String(workspace.id) === String(activeWorkspaceId)) || workspaces[0] || createDefaultWorkspaceBundle(user).workspaces[0],
    [workspaces, activeWorkspaceId, user]
  );
  const currentWorkspaceUserId = user?.id || "local-beta";
  const currentWorkspaceEmail = String(user?.email || "").toLowerCase();
  const workspaceOwnerMatchesUser = (workspace = {}) =>
    Boolean(currentWorkspaceUserId) &&
    (String(workspace.ownerUserId || "") === String(currentWorkspaceUserId) || String(workspace.owner_user_id || "") === String(currentWorkspaceUserId));
  const workspaceMemberFor = (workspaceId = activeWorkspace?.id) =>
    workspaceMembers.find((member) =>
      String(member.workspaceId || member.workspace_id) === String(workspaceId) &&
      member.status === "active" &&
      (
        String(member.userId || member.user_id || "") === String(currentWorkspaceUserId) ||
        (currentWorkspaceEmail && String(member.email || "").toLowerCase() === currentWorkspaceEmail)
      )
    );
  const activeWorkspaceMember = useMemo(
    () => workspaceMemberFor(activeWorkspace?.id),
    [workspaceMembers, activeWorkspace, currentWorkspaceUserId, currentWorkspaceEmail]
  );
  const activeWorkspaceRole = activeWorkspaceMember?.role || (workspaceOwnerMatchesUser(activeWorkspace) ? "owner" : "viewer");
  const canEditActiveWorkspace = workspaceCanEdit(activeWorkspaceRole);
  const canManageActiveWorkspace = workspaceCanManage(activeWorkspaceRole);
  const workspaceRoleForId = (workspaceId = activeWorkspace?.id) => {
    const workspace = workspaces.find((entry) => String(entry.id) === String(workspaceId)) || activeWorkspace;
    const member = workspaceMemberFor(workspace?.id);
    if (member?.role) return member.role;
    return workspaceOwnerMatchesUser(workspace) ? "owner" : "viewer";
  };
  const canEditWorkspaceId = (workspaceId = activeWorkspace?.id) => workspaceCanEdit(workspaceRoleForId(workspaceId));
  const ensureWorkspaceEditor = (workspaceId = activeWorkspace?.id) => {
    if (canEditWorkspaceId(workspaceId)) return true;
    return showAppMessage("You do not have permission to edit this workspace.");
  };
  const workspaceSelectorOptions = useMemo(
    () => workspaces.filter((workspace) =>
      workspaceMemberFor(workspace.id) || workspaceOwnerMatchesUser(workspace) || (BETA_LOCAL_MODE && currentWorkspaceUserId === "local-beta")
    ),
    [workspaces, workspaceMembers, currentWorkspaceUserId, currentWorkspaceEmail]
  );
  const destinationWorkspaceOptions = useMemo(() => {
    const visible = workspaceSelectorOptions.length ? workspaceSelectorOptions : workspaces;
    const personalish = visible.filter((workspace) => ["personal", "personal_shared", "shared_collection", "family", "team"].includes(workspace.type));
    const business = visible.filter((workspace) => ["business", "card_shop_partner", "team"].includes(workspace.type));
    return {
      vault: personalish.length ? personalish : visible,
      wishlist: personalish.length ? personalish : visible,
      forge: business.length ? business : visible,
    };
  }, [workspaceSelectorOptions, workspaces]);
  const defaultWorkspaceIdForDestination = (destination) => {
    if (destination === "forge") {
      return destinationWorkspaceOptions.forge[0]?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID;
    }
    if (["vault", "wishlist"].includes(destination)) {
      const matchingActive = destinationWorkspaceOptions[destination]?.find((workspace) => workspace.id === activeWorkspace?.id);
      return matchingActive?.id || destinationWorkspaceOptions[destination]?.[0]?.id || DEFAULT_PERSONAL_WORKSPACE_ID;
    }
    return activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID;
  };
  const forgeTabActive = ["addInventory", "inventory", "addSale", "sales", "expenses", "mileage", "reports"].includes(activeTab);
  const autoHideBlocked = Boolean(
    activeFlowModal ||
    showInventoryScanner ||
    showCatalogScanner ||
    listingReviewOpen ||
    dealFinderOpen ||
    showVaultAddForm ||
    scoutScoreModalOpen ||
    feedbackDialog ||
    suggestionConflict ||
    vaultPotentialDuplicate ||
    vaultDuplicateItem ||
    vaultForgeTransfer ||
    selectedCatalogDetailId ||
    quickAddMenuOpen ||
    menuOpen ||
    searchExpanded ||
    locationPromptOpen ||
    importAssistantOpen ||
    listingReportTarget ||
    vaultListingDecision
  );
  const autoHideResetKey = [
    activeTab,
    activeMainTab || "standalone",
    homeSubTab,
    scoutView,
    vaultSubTab,
    tideTradrSubTab,
    forgeSubTab,
    marketplaceView,
  ].join("|");
  const { headerMode } = useAutoHideHeader({
    disabled: autoHideBlocked,
    resetKey: autoHideResetKey,
  });
  const getHeaderCardClass = (className = "") =>
    `app-header-card app-header-card--${headerMode}${className ? ` ${className}` : ""}`;
  const legacyVaultAddModalEnabled = false; // Deprecated: product adds now route through Add to Multiple Places.
  const showAppUpdatePrompt = Boolean(
    appUpdate.available &&
    appUpdate.latestVersion !== dismissedUpdateVersion &&
    !autoHideBlocked &&
    !appRefreshInProgress
  );

  useEffect(() => {
    let active = true;

    async function checkForUpdate(source = "version-json") {
      try {
        const update = await checkForEmberTideUpdate();
        if (!active || !update.available) return;
        setAppUpdate({ ...update, source });
      } catch {
        // Version checks must stay quiet so offline/beta sessions are not interrupted.
      }
    }

    const onServiceWorkerUpdate = (event) => {
      setAppUpdate((current) => ({
        ...current,
        available: true,
        latestVersion: current.latestVersion || "service-worker-update",
        source: event.detail?.source || "service-worker",
      }));
    };

    checkForUpdate();
    const interval = window.setInterval(() => checkForUpdate(), 5 * 60 * 1000);
    const onVisibilityChange = () => {
      if (document.visibilityState === "visible") checkForUpdate("visibility");
    };
    document.addEventListener("visibilitychange", onVisibilityChange);
    window.addEventListener("ember-tide:update-available", onServiceWorkerUpdate);

    return () => {
      active = false;
      window.clearInterval(interval);
      document.removeEventListener("visibilitychange", onVisibilityChange);
      window.removeEventListener("ember-tide:update-available", onServiceWorkerUpdate);
    };
  }, []);

  async function handleSafeAppRefresh() {
    setAppRefreshInProgress(true);
    setVaultToast("Refreshing Ember & Tide to the newest version...");
    try {
      await refreshEmberTideApp();
    } catch (error) {
      setAppRefreshInProgress(false);
      setVaultToast(`Refresh failed: ${error.message || "try again"}`);
    }
  }

  function navigateMainTab(tab) {
    if (!confirmLeaveVaultWork()) return;
    if (tab.key === "scout") {
      setScoutView("overview");
      setScoutSubTabTarget({ tab: "overview", id: Date.now() });
    }
    if (tab.key === "tideTradr") {
      setTideTradrSubTab("overview");
      setFeatureSectionsOpen((current) => ({
        ...current,
        market_watchlist: false,
        market_deal_finder: false,
        market_sources: false,
        market_filters: false,
      }));
    }
    if (tab.key === "forge") {
      setForgeSubTab("overview");
      setFeatureSectionsOpen((current) => ({
        ...current,
        forge_inventory: false,
        forge_sales: false,
        forge_expenses: false,
        forge_mileage: false,
        forge_reports: false,
        forge_marketplace: false,
      }));
    }
    setQuickAddMenuOpen(false);
    setSearchExpanded(false);
    setActiveTab(tab.target);
  }

  function navigateTopbarSection(value) {
    const tab = topbarSectionOptions.find((option) => option.key === value);
    if (!tab) return;
    if (tab.key === "settings") {
      setQuickAddMenuOpen(false);
      setSearchExpanded(false);
      setMenuOpen(true);
      setActiveTab("menu");
      return;
    }
    navigateMainTab(tab);
  }

  function renderPageChrome({ title, subtitle, primary, secondary, quickActions = [], tabs = [], activeSubTab, setActiveSubTab }) {
    return (
      <PageHeader
        className={getHeaderCardClass("panel page-dashboard-header")}
        title={title}
        subtitle={subtitle}
        actions={(
          <>
            {primary ? <button type="button" onClick={primary.onClick}>{primary.label}</button> : null}
            {secondary ? <button type="button" className="secondary-button" onClick={secondary.onClick}>{secondary.label}</button> : null}
          </>
        )}
        tabs={tabs}
        activeTab={activeSubTab}
        onTabChange={setActiveSubTab}
      >
        {quickActions.length ? <QuickActionGrid actions={quickActions} ariaLabel={`${title} quick actions`} /> : null}
      </PageHeader>
    );
  }

  function openOperatingSystemFeature(modeKey, action = "") {
    setQuickAddMenuOpen(false);
    setSearchExpanded(false);
    if (modeKey === "vault") {
      setActiveTab("vault");
      if (action === "Open Sets") {
        if (!featureAllowed("set_completion")) return openLockedFeatureNotice("set_completion");
        setVaultSubTab("sets");
      }
      else if (action === "Portfolio") {
        if (!featureAllowed("portfolio_value")) return openLockedFeatureNotice("portfolio_value");
        setVaultSubTab("portfolio");
      }
      else setVaultSubTab("collection");
      if (action === "Add Item") openVaultQuickAdd({ stayInContext: true });
      if (action === "Search Catalog") {
        setActiveTab("market");
        setTideTradrSubTab("overview");
      }
      return;
    }
    if (modeKey === "forge") {
      setActiveTab("inventory");
      setForgeSubTab(action === "Marketplace" ? "marketplace" : "overview");
      if (action === "Add Inventory") openQuickAddAction("inventory");
      if (action === "Record Sale") openQuickAddAction("sale");
      if (action === "Add Expense") openQuickAddAction("expense");
      return;
    }
    if (modeKey === "scout") {
      setActiveTab("scout");
      if (action === "Open Predictions") {
        if (!featureAllowed("restock_predictions")) return openLockedFeatureNotice("restock_predictions");
        setScoutView("predictions");
      }
      else if (action === "Store Map") setScoutView("storeMap");
      else if (action === "Alerts" || action === "Ember Watch") setScoutView("alerts");
      else setScoutView("overview");
      setScoutSubTabTarget({ tab: action === "Alerts" || action === "Ember Watch" ? "alerts" : action === "Store Map" ? "storeMap" : "overview", id: Date.now() });
      if (action === "Submit Report") openScoutSubmitFlow({ source: "global-command" });
      if (action === "Import Intel") openScoutSubmitFlow({ action: "importIntel" });
      return;
    }
    if (modeKey === "market") {
      setActiveTab("market");
      setTideTradrSubTab(action === "Watchlist" ? "watch" : "overview");
      if (action === "Create Listing") openMarketplaceCreate("manual", {});
      if (action === "Check Deal") openDealFinderModal();
      return;
    }
    if (modeKey === "tidepool") {
      openTidepoolCommunity(action === "Deal Check" ? "Deals" : "Latest");
      if (action === "Create Post" || action === "Donation Post") openTidepoolCreatePostFlow();
      return;
    }
    if (modeKey === "catalog") {
      setActiveTab("market");
      setTideTradrSubTab("overview");
      if (action === "Market Sources") setFeatureSectionsOpen((current) => ({ ...current, market_sources: true }));
      if (action === "Suggest Correction") openFeedbackDialog("catalog_data");
      return;
    }
    if (modeKey === "deal_finder") {
      setActiveTab("market");
      openDealFinderModal();
      return;
    }
    if (modeKey === "scanner") {
      beginScanProduct("none");
      return;
    }
    if (modeKey === "kid_community") {
      setActiveTab("dashboard");
      setHomeSubTab("goals");
      updateDashboardSection("kid_community", { enabled: true });
      return;
    }
    if (modeKey === "wishlist") {
      setActiveTab("vault");
      setVaultSubTab("collection");
      setVaultFilter("wishlist");
      return;
    }
    if (modeKey === "marketplace") {
      setActiveTab("inventory");
      setForgeSubTab("marketplace");
      return;
    }
    if (modeKey === "reports") {
      setActiveTab("reports");
      return;
    }
    if (modeKey === "settings") {
      setActiveTab("menu");
      setMenuOpen(true);
      return;
    }
    if (modeKey === "admin") {
      setActiveTab(adminToolsVisible ? "adminReview" : "menu");
      setMenuOpen(!adminToolsVisible);
    }
  }

  function renderTcgOperatingSystemPanel({ compact = false } = {}) {
    const primaryAreas = [
      {
        key: "scout",
        title: "Scout",
        verb: "Find",
        summary: "Restock reports, nearby store checks, and community intel.",
        stat: `${scoutSnapshot.reports?.length || 0} reports`,
        actions: ["Open Scout", "Submit Report"],
        onOpen: () => openCommandCenterAction("scout"),
        onAction: () => openCommandCenterAction("scout", "Submit Report"),
      },
      {
        key: "vault",
        title: "Vault",
        verb: "Collect",
        summary: "Your collection, wishlist, set progress, and card records.",
        stat: `${activeVaultItems.length || 0} items`,
        actions: ["Open Vault", "Add Item"],
        onOpen: () => openCommandCenterAction("vault"),
        onAction: () => openCommandCenterAction("vault", "Add Item"),
      },
      {
        key: "market",
        title: "Market",
        verb: "Trade",
        summary: "Fair value tools, watchlist, deal checks, and listings.",
        stat: `${marketplaceListings.length || 0} listings`,
        actions: ["Open Market", "Check Deal"],
        onOpen: () => openCommandCenterAction("market"),
        onAction: () => openCommandCenterAction("market", "Check Deal"),
      },
      {
        key: "forge",
        title: "Forge",
        verb: "Build",
        summary: "Inventory, sales, expenses, receipts, and planning tools.",
        stat: `${forgeInventoryItems.length || 0} items`,
        actions: ["Open Forge", "Add Inventory"],
        onOpen: () => openCommandCenterAction("forge"),
        onAction: () => openCommandCenterAction("forge", "Add Inventory"),
      },
    ];
    const commandQuickActions = [
      { key: "report", label: "Quick Scout Report", category: "activity", onClick: () => openCommandCenterAction("scout", "Submit Report") },
      { key: "add", label: "Quick Add Item", category: "tools", onClick: () => openCommandCenterQuickAdd("vaultItem") },
      { key: "scan", label: "Scan / Review Item", category: "tools", onClick: () => openCommandCenterQuickAdd("scanProduct") },
      { key: "search", label: "Search", category: "tools", onClick: () => openCommandCenterAction("catalog", "Search Catalog") },
      { key: "import", label: "Import / Bulk Add", category: "manage", onClick: () => openCommandCenterBulkAdd() },
      { key: "watch", label: "Ember Watch", category: "activity", onClick: () => openCommandCenterAction("scout", "Ember Watch") },
      { key: "map", label: "Store Map", category: "tools", onClick: () => openCommandCenterAction("scout", "Store Map") },
      ...(adminToolsVisible ? [{ key: "admin", label: "Admin Edit", category: "manage", onClick: () => openCommandCenterAction("admin") }] : []),
    ];
    const overviewStats = [
      { label: "Scout reports", value: scoutSnapshot.reports?.length || 0 },
      { label: "Vault items", value: activeVaultItems.length || 0 },
      { label: "Market listings", value: marketplaceListings.length || 0 },
      { label: "Forge inventory", value: forgeInventoryItems.length || 0 },
      { label: "Alerts", value: (betaReadinessData.notifications || []).filter((entry) => !entry.dismissedAt && !entry.readAt).length },
      { label: "Reviews", value: adminToolsVisible ? suggestions.filter((entry) => entry.status === SUGGESTION_STATUSES.PENDING).length : phase2MarketplaceDraftListings.length || 0 },
    ];
    const missionStats = [
      { label: "Level", value: TIER_LABELS[getUserTier(subscriptionProfile)] || getUserTier(subscriptionProfile) || "Beta" },
      { label: "Streak", value: `${dailyTideToday.checkInStreak || 0} day` },
      { label: "Trust", value: scoutSnapshot.scoutProfile?.trustScore || 72 },
      { label: "Badges", value: dailyTideToday.badges?.length || 0 },
    ];
    const smartTools = [
      { key: "store-map", label: "Store Map", helper: "Find and review store intel.", category: "tools", onClick: () => openCommandCenterAction("scout", "Store Map") },
      { key: "ember-watch", label: "Ember Watch", helper: "Restock windows, reports, and watched stores.", category: "activity", onClick: () => openCommandCenterAction("scout", "Ember Watch") },
      { key: "watchlist", label: "Watchlist", helper: "Track wants and market changes.", category: "activity", onClick: () => openCommandCenterAction("market", "Watchlist") },
      { key: "daily-tide", label: "Daily Tide Report", helper: "Review today's quick loop.", category: "activity", onClick: () => closeFlowModal({ force: true }) },
      { key: "family", label: "Family Dashboard", helper: "Parent and kid-safe controls.", category: "community", onClick: () => { closeFlowModal({ force: true }); setActiveTab("dashboard"); } },
      { key: "kids", label: "Kids Program", helper: "Fair collecting for families.", category: "community", onClick: () => { closeFlowModal({ force: true }); setActiveTab("kidsProgram"); } },
      ...(adminToolsVisible ? [{ key: "admin-tools", label: "Admin tools", helper: "Review queue and moderation.", category: "manage", onClick: () => openCommandCenterAction("admin") }] : []),
    ];
    const visibleQuickActions = commandCenterTab === "all"
      ? commandQuickActions
      : commandQuickActions.filter((action) => action.category === commandCenterTab);
    const visibleSmartTools = commandCenterTab === "all"
      ? smartTools
      : smartTools.filter((tool) => tool.category === commandCenterTab);
    function openCommandCenterAction(modeKey, action = "") {
      closeFlowModal({ force: true, reset: false });
      window.setTimeout(() => openOperatingSystemFeature(modeKey, action), 0);
    }
    function openCommandCenterQuickAdd(action) {
      closeFlowModal({ force: true, reset: false });
      window.setTimeout(() => openQuickAddAction(action), 0);
    }
    function openCommandCenterBulkAdd() {
      closeFlowModal({ force: true, reset: false });
      window.setTimeout(() => openBulkAddFlow("Mixed"), 0);
    }
    return (
      <section className={`panel tcg-os-panel tcg-command-center${compact ? " tcg-os-panel-compact" : ""}`}>
        <div className="tcg-command-hero">
          <div>
            <h2>TCG Command Center</h2>
            <p>Jump into Scout, Vault, Market, or Forge.</p>
          </div>
          <div className="phase2-sync-status tcg-command-sync">
            <strong>{phase2SyncStatus.label || (phase2SyncStatus.source === "supabase" ? "Supabase connected" : "Local only mode")}</strong>
            <span>{phase2SyncStatus.message}</span>
            {phase2SyncStatus.source !== "supabase" ? (
              <button type="button" className="ghost-button" onClick={retryPhase2Sync}>Retry sync</button>
            ) : null}
          </div>
        </div>

        <div className="tcg-command-primary-grid" aria-label="Main app areas">
          {primaryAreas.map((area) => (
            <article className={`tcg-command-primary-card tcg-command-primary-${area.key}`} key={area.key}>
              <button type="button" className="tcg-command-primary-main" onClick={area.onOpen}>
                <span>{area.verb}</span>
                <strong>{area.title}</strong>
                <small>{area.summary}</small>
                <b>{area.stat}</b>
              </button>
              <div className="tcg-command-primary-actions">
                <button type="button" className="ghost-button" onClick={area.onOpen}>{area.actions[0]}</button>
                <button type="button" className="secondary-button" onClick={area.onAction}>{area.actions[1]}</button>
              </div>
            </article>
          ))}
        </div>

        <div className="tcg-command-tabs" role="tablist" aria-label="Command Center categories">
          {["all", "tools", "activity", "community", "manage"].map((tab) => (
            <button
              key={tab}
              type="button"
              className={commandCenterTab === tab ? "active" : ""}
              onClick={() => setCommandCenterTab(tab)}
            >
              {tab === "all" ? "All" : tab[0].toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>

        <section className="tcg-command-section">
          <div className="tcg-command-section-title">
            <h3>Quick Actions</h3>
            <span>{visibleQuickActions.length} shortcuts</span>
          </div>
          <div className="tcg-command-action-grid">
            {visibleQuickActions.map((action) => (
              <button type="button" className="tcg-command-action" key={action.key} onClick={action.onClick}>
                {action.label}
              </button>
            ))}
          </div>
        </section>

        <div className="tcg-command-dashboard-grid">
          <section className="tcg-command-status-card">
            <div className="tcg-command-section-title">
              <h3>Mission / Status</h3>
              <span>Private beta</span>
            </div>
            <div className="tcg-command-stat-row">
              {missionStats.map((stat) => (
                <span key={stat.label}>
                  <small>{stat.label}</small>
                  <strong>{stat.value}</strong>
                </span>
              ))}
            </div>
          </section>

          <section className="tcg-command-overview-card">
            <div className="tcg-command-section-title">
              <h3>System Overview</h3>
              <span>Live counts</span>
            </div>
            <div className="tcg-command-overview-grid">
              {overviewStats.map((stat) => (
                <span key={stat.label}>
                  <small>{stat.label}</small>
                  <strong>{stat.value}</strong>
                </span>
              ))}
            </div>
          </section>
        </div>

        {visibleSmartTools.length ? (
          <section className="tcg-command-section">
            <div className="tcg-command-section-title">
              <h3>Smart Tools</h3>
              <span>{commandCenterTab === "all" ? "Filtered by chips" : commandCenterTab}</span>
            </div>
            <div className="tcg-command-tool-grid">
              {visibleSmartTools.map((tool) => (
                <button type="button" className="tcg-command-tool" key={tool.key} onClick={tool.onClick}>
                  <strong>{tool.label}</strong>
                  <small>{tool.helper}</small>
                </button>
              ))}
            </div>
          </section>
        ) : (
          <div className="empty-state-card tcg-command-empty">
            <h3>No tools in this category yet.</h3>
            <p>Switch tabs or use the four main actions above.</p>
          </div>
        )}
        {commandCenterTab === "all" && (
          <section className="tcg-command-section tcg-command-recent">
            <div className="tcg-command-section-title">
              <h3>Recent Workflow</h3>
              <span>Compact</span>
            </div>
            <div className="tcg-command-recent-grid">
              {[
                phase2RecentDeals[0] ? { key: "deal", label: phase2RecentDeals[0].title || "Saved deal check", value: money(phase2RecentDeals[0].askingPrice), onClick: () => openCommandCenterAction("deal_finder") } : null,
                phase2RecentScannerIntakes[0] ? { key: "scan", label: phase2RecentScannerIntakes[0].extractedClues?.itemName || phase2RecentScannerIntakes[0].rawValue || "Saved scanner intake", value: phase2WorkflowSyncLabel, onClick: () => openCommandCenterAction("scanner") } : null,
                phase2RecentReceipts[0] ? { key: "receipt", label: phase2RecentReceipts[0].merchant || "Saved receipt", value: money(phase2RecentReceipts[0].total), onClick: () => openCommandCenterAction("forge") } : null,
                phase2MarketplaceDraftListings[0] ? { key: "market", label: phase2MarketplaceDraftListings[0].title || "Marketplace draft", value: money(phase2MarketplaceDraftListings[0].askingPrice), onClick: () => openCommandCenterAction("market") } : null,
              ].filter(Boolean).slice(0, 4).map((entry) => (
                <button type="button" key={entry.key} className="tcg-command-recent-item" onClick={entry.onClick}>
                  <strong>{entry.label}</strong>
                  <small>{entry.value}</small>
                </button>
              ))}
              {!phase2RecentDeals.length && !phase2RecentScannerIntakes.length && !phase2RecentReceipts.length && !phase2MarketplaceDraftListings.length ? (
                <span className="tcg-command-recent-empty">No recent workflow yet.</span>
              ) : null}
              </div>
          </section>
        )}
      </section>
    );
  }

  const appSearchResults = useMemo(() => {
    const queryInfo = expandSearchQuery(appSearchQuery);
    userSearchAliases.forEach((entry) => {
      const alias = normalizeSearchText(entry.alias);
      const canonical = normalizeSearchText(entry.canonical);
      if (alias && canonical && (queryInfo.normalized.includes(alias) || queryInfo.tokens.includes(alias))) {
        queryInfo.phrases.push(canonical, ...searchTokens(canonical));
      }
    });
    if (queryInfo.normalized.length < 2) return [];

    function setAliasesFor(setName) {
      return SET_SEARCH_METADATA[setName]?.setAliases || [];
    }

    function productTypeAliasesFor(type) {
      return PRODUCT_TYPE_ALIASES[type] || [];
    }

    function pokemonAliasesFor(name) {
      return POKEMON_ALIASES[name] || [];
    }

    function rarityAliasesFor(rarity, variant) {
      return [...(RARITY_VARIANT_ALIASES[rarity] || []), ...(RARITY_VARIANT_ALIASES[variant] || [])];
    }

    const catalogResults = catalogProducts.map((product) => {
      const isCard = product.catalogType === "card";
      const setAliases = [...setAliasesFor(product.setName), ...(product.setAliases || [])];
      const candidate = {
        fields: [
          product.name,
          product.productName,
          product.cardName,
          product.pokemonName,
          product.setName,
          product.setCode,
          setAliases,
          product.productType,
          product.rarity,
          product.variant,
          product.cardNumber,
          product.barcode,
          product.upc,
          product.sku,
          product.externalProductId,
          product.tcgplayerProductId,
          product.marketSource,
          product.priceSubtype,
          product.sourceUrl,
          product.marketUrl,
          product.releaseYear,
        ],
        exactIds: [product.barcode, product.upc, product.sku, product.externalProductId, product.tcgplayerProductId],
        cardNumbers: [product.cardNumber],
        setCodes: [product.setCode],
        aliases: [...setAliases, ...productTypeAliasesFor(product.productType), ...pokemonAliasesFor(product.pokemonName), ...rarityAliasesFor(product.rarity, product.variant)],
        names: [product.name, product.productName, product.cardName],
        productTypeAliases: productTypeAliasesFor(product.productType),
        pokemonAliases: pokemonAliasesFor(product.pokemonName),
        rarityAliases: rarityAliasesFor(product.rarity, product.variant),
      };
      const { score, reason } = scoreSearchCandidate(queryInfo, candidate);
      const marketInfo = getTideTradrMarketInfo(product);
      return {
        id: `${isCard ? "card" : "product"}-${product.id}`,
        category: isCard ? "Cards" : "Products",
        title: product.name || product.productName || product.cardName,
        subtitle: isCard
          ? `${product.setCode || product.setName || "Card"}${product.cardNumber ? ` • ${product.cardNumber}` : ""}${product.rarity ? ` • ${product.rarity}` : ""} • ${MARKET_STATUS_LABELS[marketInfo.marketStatus] || "Market"}`
          : `${product.setCode || product.setName || "Set"} • ${product.productType || "Sealed product"} • ${MARKET_STATUS_LABELS[marketInfo.marketStatus] || "Market"}`,
        source: product,
        score,
        reason,
      };
    });

    const inventoryResults = items.map((item) => {
      const setAliases = setAliasesFor(item.expansion);
      const candidate = {
        fields: [item.name, item.expansion, item.setCode, setAliases, item.productType, item.store, item.barcode, item.sku, item.catalogProductName],
        exactIds: [item.barcode, item.sku],
        setCodes: [item.setCode],
        aliases: [...setAliases, ...productTypeAliasesFor(item.productType)],
        names: [item.name, item.catalogProductName],
        productTypeAliases: productTypeAliasesFor(item.productType),
      };
      const { score, reason } = scoreSearchCandidate(queryInfo, candidate);
      const isVault = item.status === "Personal Collection" || item.status === "Held";
      return {
        id: `${isVault ? "vault" : "inventory"}-${item.id}`,
        category: isVault ? "Vault" : "Inventory",
        title: item.name,
        subtitle: `${isVault ? item.status : `Qty ${item.quantity}`} • ${money(item.marketPrice || item.unitCost)}`,
        source: item,
        score: score * 0.82,
        reason,
      };
    });

    const storeResults = scoutSnapshot.stores.map((store) => {
      const candidate = {
        fields: [store.name, store.nickname, store.chain, store.city, store.address, store.region, store.zip, store.sku, STORE_ALIASES[store.chain]],
        exactIds: [store.sku, store.placeId],
        aliases: [...(STORE_ALIASES[store.chain] || []), store.nickname],
        names: [store.name, store.nickname],
      };
      const { score, reason } = scoreSearchCandidate(queryInfo, candidate);
      return {
        id: `store-${store.id}`,
        category: "Stores",
        title: store.nickname || store.name,
        subtitle: `${store.chain || "Store"} • ${store.city || ""}`,
        source: store,
        score: score * 0.72,
        reason,
      };
    });

    const allReports = [...(scoutSnapshot.reports || []), ...(scoutSnapshot.tidepoolReports || [])];
    const reportResults = allReports.map((report) => {
      const candidate = {
        fields: [report.itemName, report.productName, report.reportText, report.notes, report.storeName, report.reportType, report.upc, report.sku],
        exactIds: [report.upc, report.sku],
        aliases: [],
        names: [report.itemName, report.productName],
      };
      const { score, reason } = scoreSearchCandidate(queryInfo, candidate);
      return {
        id: `report-${report.id || report.reportId}`,
        category: "Reports",
        title: report.itemName || report.productName || report.reportType || "Scout report",
        subtitle: `${report.storeName || "Scout"} • ${report.reportType || report.stockStatus || "Report"}`,
        source: report,
        score: score * 0.66,
        reason,
      };
    });
    const tidepoolPostResults = tidepoolPosts.map((post) => {
      const candidate = {
        fields: [post.title, post.body, post.postType, post.city, post.zip, post.verificationStatus],
        exactIds: [],
        aliases: [],
        names: [post.title],
      };
      const { score, reason } = scoreSearchCandidate(queryInfo, candidate);
      return {
        id: `tidepool-${post.postId}`,
        category: "Reports",
        title: post.title || post.postType,
        subtitle: `Tidepool - ${post.postType} - ${post.verificationStatus}`,
        source: post,
        score: score * 0.66,
        reason,
      };
    });

    return [...catalogResults, ...inventoryResults, ...storeResults, ...reportResults, ...tidepoolPostResults]
      .filter((result) => result.score > 25)
      .sort((a, b) => b.score - a.score)
      .slice(0, 24);
  }, [appSearchQuery, catalogProducts, items, marketPriceCache, scoutSnapshot, tidepoolPosts, userSearchAliases]);

  const appSearchSuggestion = useMemo(() => {
    const queryInfo = expandSearchQuery(appSearchQuery);
    if (queryInfo.normalized.length < 2 || appSearchResults.length > 0) return "";
    const alias = SEARCH_ALIAS_ENTRIES.find((entry) => normalizeSearchText(entry.alias).startsWith(queryInfo.tokens[0] || ""));
    return alias?.canonical || "";
  }, [appSearchQuery, appSearchResults.length]);

  function closeSearchResults() {
    setAppSearchQuery("");
    setSearchExpanded(false);
  }

  function scrollToPageTop() {
    const prefersReducedMotion =
      typeof window !== "undefined" &&
      window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches;
    window.scrollTo({
      top: 0,
      left: 0,
      behavior: prefersReducedMotion ? "auto" : "smooth",
    });
  }

  function scrollToResultsTop(targetRef = catalogResultsRef) {
    if (typeof window === "undefined") return;
    const prefersReducedMotion = window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches;
    const target = targetRef?.current;
    if (!target) {
      scrollToPageTop();
      return;
    }
    const top = Math.max(0, target.getBoundingClientRect().top + window.scrollY - 96);
    window.scrollTo({
      top,
      left: 0,
      behavior: prefersReducedMotion ? "auto" : "smooth",
    });
  }

  function openTidepoolCommunity(filter = "Latest") {
    setTidepoolOpen(true);
    setTidepoolFilter(filter);
    setActiveTab("tidepool");
    setMenuOpen(false);
    setQuickAddMenuOpen(false);
    setSearchExpanded(false);
  }

  function openTidepoolCreatePostFlow() {
    setActiveTab("tidepool");
    setTidepoolOpen(true);
    openFlowModal("tidepoolCreatePost", { size: "medium", source: "tidepool" });
  }

  function viewSearchResult(result) {
    if (result.category === "Products" || result.category === "Cards") {
      setTideTradrLookupId(result.source.id);
      setSelectedCatalogDetailId(result.source.id);
      setActiveTab("market");
      setTideTradrSubTab("catalog");
    } else if (result.category === "Inventory") {
      setInventorySearch(result.source.name || "");
      setActiveTab("inventory");
    } else if (result.category === "Vault") {
      setActiveTab("vault");
      setFeatureSectionsOpen((current) => ({ ...current, vault_collection_items: true }));
    } else if (result.category === "Stores" || result.category === "Reports") {
      if (result.category === "Stores") {
        setActiveTab("scout");
        setFeatureSectionsOpen((current) => ({ ...current, scout_stores: true }));
        setScoutSubTabTarget({ tab: "stores", id: Date.now() });
      } else {
        openTidepoolCommunity("Latest");
      }
    }
    setSearchExpanded(false);
  }

  function favoriteSearchStore(store) {
    const nextStores = scoutSnapshot.stores.map((candidate) =>
      String(candidate.id) === String(store.id) ? { ...candidate, favorite: true } : candidate
    );
    setScoutSnapshot((current) => ({ ...current, stores: nextStores }));
    const saved = JSON.parse(localStorage.getItem(SCOUT_STORAGE_KEY) || "{}");
    localStorage.setItem(SCOUT_STORAGE_KEY, JSON.stringify({ ...saved, stores: nextStores }));
  }

  function renderSearchActions(result) {
    if (result.category === "Products" || result.category === "Cards") {
      return (
        <>
          <button type="button" onClick={() => viewSearchResult(result)}>View details</button>
          <button type="button" className="secondary-button" onClick={() => {
            openProductAddFlow({ product: result.source, source: "global-search-vault", destinations: { vault: true } });
            setSearchExpanded(false);
          }}>Add to Vault</button>
          <button type="button" className="secondary-button" onClick={() => {
            openProductAddFlow({
              product: result.source,
              source: "global-search-wishlist",
              destinations: { wishlist: true },
              seed: { wishlist: { ...BLANK_MULTI_DESTINATION_FORM.wishlist, addToMarketWatch: true } },
            });
            setSearchExpanded(false);
          }}>Wishlist</button>
          <button type="button" className="secondary-button" onClick={() => viewSearchResult(result)}>More</button>
        </>
      );
    }
    if (result.category === "Stores") {
      return (
        <>
          <button type="button" onClick={() => viewSearchResult(result)}>View store</button>
          <button type="button" className="secondary-button" onClick={() => favoriteSearchStore(result.source)}>Favorite store</button>
        </>
      );
    }
    if (result.category === "Reports") {
      return <button type="button" onClick={() => viewSearchResult(result)}>Open report</button>;
    }
    return <button type="button" onClick={() => viewSearchResult(result)}>View item</button>;
  }

  function toggleMenuSection(key) {
    setMenuSectionsOpen((current) => (current[key] ? {} : { [key]: true }));
  }

  function runMenuAction(action) {
    action();
    setMenuOpen(false);
  }

  function openLockedFeatureNotice(featureKey) {
    setLockedFeatureKey(featureKey);
    setQuickAddMenuOpen(false);
  }

  function requestLockedFeatureAccess(featureKey) {
    const label = FEATURE_LABELS[featureKey] || featureKey;
    setLockedFeatureKey("");
    openFeedbackDialog("feature", {
      whatHappened: `Request beta access for ${label}.`,
      metadata: { featureKey },
    });
  }

  function openFeedbackDialog(type, defaults = {}) {
    const now = new Date().toISOString();
    setFeedbackDialog(type);
    setFeedbackForm({
      whatHappened: defaults.whatHappened || "",
      page: defaults.page || activeTabLabel,
      steps: defaults.steps || "",
      screenshotName: "",
      metadata: {
        appVersion: "Ember & Tide beta web app",
        route: activeTab,
        feedbackCategory: type,
        ...(defaults.metadata || {}),
        device:
          typeof window !== "undefined"
            ? `${window.innerWidth}x${window.innerHeight}`
            : "Unknown",
        betaMode: BETA_LOCAL_MODE ? "Private beta" : "Cloud-ready",
        timestamp: now,
      },
    });
  }

  function feedbackFormHasDraft() {
    return Boolean(
      String(feedbackForm.whatHappened || "").trim() ||
      String(feedbackForm.steps || "").trim() ||
      String(feedbackForm.screenshotName || "").trim()
    );
  }

  function closeFeedbackDialog(force = false) {
    if (!force && feedbackFormHasDraft() && !window.confirm("Discard changes?")) {
      return false;
    }
    setFeedbackDialog(null);
    setFeedbackForm({ whatHappened: "", page: "", steps: "", screenshotName: "", metadata: {} });
    return true;
  }

  function updateBetaReadinessData(updater) {
    const next = saveBetaReadinessData(updater);
    setBetaReadinessData(next);
    return next;
  }

  function addAuditLog(action, entityType, entityId, metadata = {}) {
    updateBetaReadinessData((current) => ({
      ...current,
      auditLogs: [
        {
          id: makeId("audit"),
          actorUserId: user?.id || null,
          workspaceId: activeWorkspace?.id || null,
          action,
          entityType,
          entityId,
          metadata,
          createdAt: new Date().toISOString(),
        },
        ...(current.auditLogs || []),
      ].slice(0, 250),
    }));
  }

  function logAppError(action, error, metadata = {}, severity = "normal") {
    const safeMetadata = {
      page: activeTab,
      ...(metadata || {}),
    };
    delete safeMetadata.password;
    delete safeMetadata.token;
    delete safeMetadata.receiptImage;
    delete safeMetadata.childFirstName;
    const entry = {
      id: makeId("app-error"),
      userId: user?.id || null,
      workspaceId: activeWorkspace?.id || null,
      page: activeTabLabel,
      action,
      errorMessage: error?.message || String(error || "Unknown error"),
      errorCode: error?.code || "",
      severity,
      metadata: safeMetadata,
      userAgent: typeof navigator !== "undefined" ? navigator.userAgent : "",
      createdAt: new Date().toISOString(),
    };
    updateBetaReadinessData((current) => ({
      ...current,
      appErrorLogs: [entry, ...(current.appErrorLogs || [])].slice(0, 200),
    }));
    return entry;
  }

  function addBetaNotification({ type = "account_notice", title, message, actionUrl = "" }) {
    updateBetaReadinessData((current) => ({
      ...current,
      notifications: [
        {
          id: makeId("notification"),
          userId: user?.id || "local-beta",
          workspaceId: activeWorkspace?.id || "",
          type,
          channel: "in_app",
          title,
          message,
          actionUrl,
          createdAt: new Date().toISOString(),
        },
        ...(current.notifications || []),
      ].slice(0, 50),
    }));
  }

  function submitFeedbackDialog(event) {
    event.preventDefault();
    const payload = {
      id: makeId(feedbackDialog || "feedback"),
      type: feedbackDialog || "feedback",
      ...feedbackForm,
      createdAt: new Date().toISOString(),
    };
    try {
      const existing = JSON.parse(localStorage.getItem(FEEDBACK_STORAGE_KEY) || "[]");
      localStorage.setItem(FEEDBACK_STORAGE_KEY, JSON.stringify([payload, ...(Array.isArray(existing) ? existing : [])]));
    } catch (error) {
      console.warn("Unable to save beta feedback", error);
      logAppError("beta_feedback_submit", error, { feedbackType: feedbackDialog }, "normal");
      setVaultToast("Could not submit right now. Please try again or export beta data.");
      return;
    }
    updateBetaReadinessData((current) => ({
      ...current,
      betaFeedback: [
        {
          id: payload.id,
          userId: user?.id || null,
          workspaceId: activeWorkspace?.id || null,
          feedbackType: feedbackDialogCopy?.title || feedbackDialog || "Feedback",
          page: payload.page || activeTabLabel,
          title: payload.whatHappened || "Beta feedback",
          description: payload.steps || payload.whatHappened || "No details provided.",
          severity: feedbackDialog === "bug" ? "normal" : "normal",
          status: "new",
          screenshotUrl: payload.screenshotName || "",
          deviceInfo: payload.metadata || {},
          browserInfo: typeof navigator !== "undefined" ? navigator.userAgent : "",
          appVersion: "Ember & Tide beta web app",
          createdAt: payload.createdAt,
        },
        ...(current.betaFeedback || []),
      ],
    }));
    if (["catalog_data", "store_data", "market_data"].includes(feedbackDialog)) {
      const suggestionMeta = {
        catalog_data: {
          suggestionType: SUGGESTION_TYPES.CORRECT_CATALOG_PRODUCT,
          targetTable: "catalog_items",
        },
        store_data: {
          suggestionType: SUGGESTION_TYPES.EDIT_STORE_DETAILS,
          targetTable: "stores",
        },
        market_data: {
          suggestionType: SUGGESTION_TYPES.CORRECT_MSRP,
          targetTable: "product_market_price_current",
        },
      }[feedbackDialog];
      const userInfo = getSuggestionUserInfo();
      const result = submitSuggestion({
        ...suggestionMeta,
        ...userInfo,
        submittedData: {
          title: feedbackForm.whatHappened,
          details: feedbackForm.steps,
          page: feedbackForm.page,
          category: feedbackDialog,
          device: feedbackForm.metadata?.device,
        },
        notes: feedbackForm.steps || feedbackForm.whatHappened || "Data issue submitted from feedback dialog.",
        source: "feedback-dialog",
        visibility: "admin_review",
      });
      if (!result.ok && result.reason === "duplicate") {
        setSuggestionConflict({
          input: {
            ...suggestionMeta,
            ...userInfo,
            submittedData: {
              title: feedbackForm.whatHappened,
              details: feedbackForm.steps,
              page: feedbackForm.page,
              category: feedbackDialog,
              device: feedbackForm.metadata?.device,
            },
            notes: feedbackForm.steps || feedbackForm.whatHappened || "Data issue submitted from feedback dialog.",
            source: "feedback-dialog",
            visibility: "admin_review",
          },
          duplicate: result.duplicate,
        });
      } else {
        setSuggestions(result.suggestions);
      }
    }
    closeFeedbackDialog(true);
    setVaultToast(
      feedbackDialog === "bug"
        ? "Bug report submitted. We'll review it."
        : feedbackDialog === "feature"
          ? "Feature request submitted."
          : ["catalog_data", "store_data", "market_data"].includes(feedbackDialog)
            ? "Data issue submitted for review."
            : "Thanks - feedback submitted."
    );
  }

  function updateCloudSyncPreference(mode) {
    setCloudSyncPreference(mode);
    setVaultToast(
      mode === "cloud"
        ? "Cloud sync preference saved. User-owned beta data still stays local until sign-in sync is connected."
        : "Private beta storage preference saved."
    );
  }

  function accountEmail() {
    return String(user?.email || authEmail || currentUserProfile?.email || "").trim();
  }

  function betaAccessMode() {
    return betaReadinessData.readiness?.betaAccessMode || "open_beta";
  }

  function userBetaAccessStatus(profile = currentUserProfile) {
    if (betaAccessMode() === "open_beta") return "approved";
    const profileStatus = profile?.betaAccessStatus || profile?.beta_access_status;
    const localStatus = (betaReadinessData.betaAccessUsers || []).find((entry) => {
      const email = String(entry.email || "").toLowerCase();
      return String(entry.userId || "") === String(user?.id || "") || (accountEmail() && email === accountEmail().toLowerCase());
    })?.status;
    return profileStatus || localStatus || "pending";
  }

  function betaAccessAllowed(profile = currentUserProfile) {
    return betaAccessMode() === "open_beta" || userBetaAccessStatus(profile) === "approved" || actualAdminUser;
  }

  async function saveProfileSettings(event) {
    event.preventDefault();
    const firstName = normalizePersonName(profileForm.firstName);
    const lastName = normalizePersonName(profileForm.lastName);
    const validationError = validateSignupFullName(firstName, lastName);
    if (validationError) {
      setVaultToast(validationError);
      return;
    }
    const fullName = `${firstName} ${lastName}`.trim();
    const displayName = normalizePersonName(profileForm.displayName || fullName);
    const preferredRegion = String(profileForm.preferredRegion || "Hampton Roads / 757").trim();
    setProfileSaving(true);
    try {
      const nextProfile = {
        ...currentUserProfile,
        firstName,
        lastName,
        fullName,
        displayName,
        preferredRegion,
        preferred_region: preferredRegion,
        updatedAt: new Date().toISOString(),
      };
      if (signedInWithSupabase && isSupabaseConfigured && supabase) {
        const { error } = await supabase.from("profiles").upsert(
          {
            id: user.id,
            email: user.email || currentUserProfile.email || "",
            first_name: firstName,
            last_name: lastName,
            full_name: fullName,
            display_name: displayName,
            preferred_region: preferredRegion,
            updated_at: new Date().toISOString(),
          },
          { onConflict: "id" }
        );
        if (error) throw error;
      }
      setCurrentUserProfile(nextProfile);
      setVaultToast("Profile updated.");
    } catch (error) {
      logAppError("profile_update", error, {}, "normal");
      setVaultToast(`Profile update failed: ${error.message || "try again"}`);
    } finally {
      setProfileSaving(false);
    }
  }

  function submitDataRequest(event) {
    event.preventDefault();
    const email = String(dataRequestForm.email || accountEmail()).trim();
    if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setVaultToast("Enter a valid email for the privacy request.");
      return;
    }
    const request = {
      id: makeId("data-request"),
      userId: user?.id || null,
      workspaceId: activeWorkspace?.id || null,
      email,
      requestType: dataRequestForm.requestType,
      message: String(dataRequestForm.message || "").trim(),
      status: "new",
      createdAt: new Date().toISOString(),
    };
    updateBetaReadinessData((current) => ({
      ...current,
      dataRequests: [request, ...(current.dataRequests || [])],
    }));
    setDataRequestForm({ requestType: "data_export", email, message: "" });
    setVaultToast("Privacy request submitted for admin review.");
  }

  function updateDataRequestStatus(requestId, status) {
    if (!adminToolsVisible) return;
    updateBetaReadinessData((current) => ({
      ...current,
      dataRequests: (current.dataRequests || []).map((entry) =>
        entry.id === requestId ? { ...entry, status, reviewedBy: user?.id || "admin", reviewedAt: new Date().toISOString() } : entry
      ),
    }));
    addAuditLog("data_request_status_update", "data_request", requestId, { status });
  }

  function updateBetaAccessMode(mode) {
    if (!adminToolsVisible || !BETA_ACCESS_MODES.includes(mode)) return;
    updateBetaReadinessData((current) => ({
      ...current,
      readiness: { ...(current.readiness || {}), betaAccessMode: mode },
    }));
  }

  function setUserAdminNote(targetUserId, note) {
    if (!adminToolsVisible) return;
    updateBetaReadinessData((current) => {
      const existing = current.userAdminNotes || [];
      const next = existing.filter((entry) => String(entry.userId) !== String(targetUserId));
      return {
        ...current,
        userAdminNotes: [
          { id: makeId("user-note"), userId: targetUserId, note, createdBy: user?.id || "admin", createdAt: new Date().toISOString() },
          ...next,
        ],
      };
    });
  }

  function updateBetaAccessUser(targetUser, status) {
    if (!adminToolsVisible || !BETA_ACCESS_STATUSES.includes(status)) return;
    const now = new Date().toISOString();
    updateBetaReadinessData((current) => {
      const existing = current.betaAccessUsers || [];
      const rest = existing.filter((entry) => String(entry.userId || entry.email) !== String(targetUser.userId || targetUser.email));
      return {
        ...current,
        betaAccessUsers: [
          {
            userId: targetUser.userId || "",
            email: targetUser.email || "",
            fullName: targetUser.fullName || targetUser.displayName || "",
            status,
            updatedAt: now,
            approvedAt: status === "approved" ? now : "",
            approvedBy: status === "approved" ? user?.id || "admin" : "",
          },
          ...rest,
        ],
      };
    });
    addAuditLog("beta_access_update", "profile", targetUser.userId || null, { email: targetUser.email, status });
  }

  function createAdminAnnouncement() {
    if (!adminToolsVisible) return;
    addBetaNotification({
      type: "announcement",
      title: "New from Ember & Tide!",
      message: "Admin-created announcement draft. Review copy before making this public in a backend-managed announcement system.",
      actionUrl: "/",
    });
    addAuditLog("announcement_create_draft", "announcement", "local-draft", { source: "admin_dashboard" });
    setVaultToast("Announcement draft added to local New Stuff notifications.");
  }

  function toggleArrayValue(values = [], value) {
    return values.includes(value) ? values.filter((entry) => entry !== value) : [...values, value];
  }

  function updateKidsProgramField(field, value) {
    setKidsProgramForm((current) => ({ ...current, [field]: value }));
  }

  function submitKidsProgramApplication(event) {
    event.preventDefault();
    if (guestPreviewActive || !user) {
      setVaultToast("Create a free account to apply for Kids Program access.");
      return;
    }
    const parentName = String(kidsProgramForm.parentName || currentUserProfile?.fullName || currentUserProfile?.displayName || "").trim();
    const email = String(kidsProgramForm.email || accountEmail()).trim();
    if (!parentName || !email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setVaultToast("Parent/guardian name and a valid email are required.");
      return;
    }
    if (!kidsProgramForm.agreesNoResale || !kidsProgramForm.consentContact) {
      setVaultToast("Please agree to Kids Program rules and contact consent before applying.");
      return;
    }
    const now = new Date().toISOString();
    const application = {
      id: makeId("kids-program"),
      userId: user?.id || "",
      parentName,
      email,
      childFirstName: String(kidsProgramForm.childFirstName || "").trim(),
      childAgeRange: String(kidsProgramForm.childAgeRange || "").trim(),
      zipCode: String(kidsProgramForm.zipCode || "").trim(),
      favoritePokemon: String(kidsProgramForm.favoritePokemon || "").trim(),
      collectingInterest: String(kidsProgramForm.collectingInterest || "").trim(),
      reason: String(kidsProgramForm.reason || "").trim(),
      requestedAccess: kidsProgramForm.requestedAccess,
      agreesNoResale: true,
      consentText: "I agree Ember & Tide may contact me about Kids Program opportunities.",
      status: "pending_review",
      createdAt: now,
      updatedAt: now,
    };
    updateBetaReadinessData((current) => ({
      ...current,
      kidsApplications: [
        application,
        ...(current.kidsApplications || []).filter((entry) => {
          const entryUser = String(entry.userId || entry.user_id || "");
          const entryEmail = String(entry.email || "").toLowerCase();
          return entryUser !== String(user?.id || "") && entryEmail !== email.toLowerCase();
        }),
      ],
    }));
    addBetaNotification({
      type: "kids_program_update",
      title: "Kids Program application received",
      message: "Your application is pending review.",
      actionUrl: "/kids-program",
    });
    setVaultToast("Kids Program application submitted for review.");
  }

  function updateKidsProgramApplicationStatus(applicationId, status) {
    if (!adminToolsVisible) return;
    const now = new Date().toISOString();
    updateBetaReadinessData((current) => ({
      ...current,
      kidsApplications: (current.kidsApplications || []).map((entry) =>
        entry.id === applicationId
          ? {
              ...entry,
              status,
              reviewedBy: user?.id || "admin",
              reviewedAt: now,
              updatedAt: now,
            }
          : entry
      ),
    }));
    addAuditLog("kids_program_status_update", "kids_program_application", applicationId, { status });
    setVaultToast(`Kids Program application marked ${status}.`);
  }

