      subtotal: 39.05,
      tax: 0.99,
      discounts: 0,
      total: 40.04,
      paymentMethod: "QA test",
      receiptImageUrl: "",
      source: "manual",
      receiptHash: `qa-receipt-${Date.now()}`,
