  function openVaultCatalogSearchFlow(options = {}) {
    setActiveTab("vault");
    setVaultCatalogSearchQuery(options.query || "");
    openFlowModal("vaultCatalogSearch", { size: "large", source: options.source || "vault" });
  }

  function openVaultScanFlow() {
    setActiveTab("vault");
    openFlowModal("vaultScan", { size: "small", source: "vault" });
  }

  function openVaultImportCollectionFlow() {
    setActiveTab("vault");
    openInventoryImportAssistant("Vault", {
      mode: BATCH_INTAKE_MODES.TRANSFER,
      sourceType: "spreadsheet_csv",
      source: "vault-import",
      resetRows: false,
    });
  }

  function openBulkAddFlow(context = "Mixed") {
    openInventoryImportAssistant(context, {
      mode: BATCH_INTAKE_MODES.BULK_ADD,
      sourceType: "bulk_paste",
      source: "bulk-add",
      resetRows: false,
    });
  }

  function openAddActionSheet(source = "topbar") {
    openFlowModal("addActionSheet", { size: "small", source });
  }

  function runAddSheetAction(action) {
    setActiveFlowModal(null);
    window.setTimeout(() => openQuickAddAction(action), 0);
  }

  function openQuickFindFlow(options = {}) {
    setQuickFindForm(BLANK_QUICK_FIND_FORM);
    if (options.source === "market") setActiveTab("market");
    openFlowModal("quickFind", { size: "small", source: options.source || "tidetradr" });
  }

  function openMultiDestinationAddFlow(options = {}) {
    resetMultiDestinationForm(options.seed || {});
    openFlowModal("multiDestinationAdd", { size: "medium", source: options.source || "quick-add" });
  }

  function openMultiDestinationAddForProduct(product, options = {}) {
    if (!product) return;
    setCatalogProducts((current) => [
      product,
      ...current.filter((entry) => String(entry.id) !== String(product.id)),
    ]);
    resetMultiDestinationForm(buildMultiDestinationSeedFromProduct(product, options.seed || {}));
    openFlowModal("multiDestinationAdd", { size: "medium", source: options.source || "vault-catalog" });
  }

  function destinationDefaults(overrides = {}) {
    return {
      vault: false,
      wishlist: false,
      forge: false,
      tidetradr: false,
      ...overrides,
    };
  }

  function openProductAddFlow({ product = null, source = "quick-add", seed = {}, destinations = {} } = {}) {
    const nextSeed = {
      ...seed,
      destinations: destinationDefaults({ ...(seed.destinations || {}), ...destinations }),
    };
    if (product) return openMultiDestinationAddForProduct(product, { source, seed: nextSeed });
    return openMultiDestinationAddFlow({ source, seed: nextSeed });
  }

  function openVaultMoveToForgeFlow() {
    setActiveTab("vault");
    openFlowModal("vaultMoveToForge", { size: "medium", source: "vault" });
  }

  function createQuickScoutReportDraft(overrides = {}) {
    const now = new Date();
    return {
      reportType: "stock_on_shelf",
      proofType: "manual",
      storeId: "",
      storeName: "",
      retailer: "",
      city: "",
      address: "",
      manualLocation: "",
      storeSearch: "",
      productCategory: "Pokemon",
      productName: "",
      quantity: "",
      price: "",
      note: "",
      proofText: "",
      photoUrl: "",
      stockLeft: "not_sure",
      dateMode: "today",
      reportDate: getLocalDateKey(now),
      reportTime: getLocalTimeKey(now),
      dayOfWeek: SCOUT_WEEKDAYS[now.getDay()],
      guessedTimeWindow: "",
      confidenceSelfRating: "50",
      visibility: "public",
      ...overrides,
    };
  }

  function getScoutQuickStoreName(store = {}) {
    return store.nickname || store.storeName || store.name || store.locationName || "Store location";
  }

  function getScoutQuickRetailer(store = {}) {
    return store.retailer || store.chain || store.storeGroup || store.banner || "Retailer";
  }

  function getScoutQuickStores() {
    const seen = new Set();
    const reportStores = [...(scoutSnapshot.reports || []), ...(scoutSnapshot.tidepoolReports || [])]
      .map((report) => ({
        id: report.storeId || report.store_id || "",
        name: report.storeName || report.store_name || "",
        nickname: report.storeName || report.store_name || "",
        retailer: report.retailer || report.chain || "",
        chain: report.retailer || report.chain || "",
        city: report.city || "",
        address: report.address || "",
        region: report.region || "",
        source: "scout-report",
      }))
      .filter((store) => store.name || store.id);
    return [...(scoutSnapshot.stores || []), ...reportStores, ...VIRGINIA_STORES_SEED]
      .filter(Boolean)
      .filter((store, index) => {
        const key = String(store.id || `${getScoutQuickRetailer(store)}-${getScoutQuickStoreName(store)}-${store.city || index}`).toLowerCase();
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      });
  }

  function findScoutQuickStore(storeLike = {}) {
    const explicitId = storeLike.storeId || storeLike.id || "";
    const storeName = getScoutQuickStoreName(storeLike).toLowerCase();
    const retailer = getScoutQuickRetailer(storeLike).toLowerCase();
    return getScoutQuickStores().find((store) => {
      if (explicitId && String(store.id) === String(explicitId)) return true;
      return getScoutQuickStoreName(store).toLowerCase() === storeName && getScoutQuickRetailer(store).toLowerCase() === retailer;
    });
  }

  function buildQuickScoutStoreDraft(store = {}) {
    if (!store || !Object.keys(store).length) return {};
    return {
      storeId: store.id || store.storeId || "",
      storeName: getScoutQuickStoreName(store),
      retailer: getScoutQuickRetailer(store),
      city: store.city || store.addressCity || store.region || "",
      address: store.address || store.streetAddress || "",
      manualLocation: "",
      storeSearch: "",
    };
  }

  function updateQuickScoutReportForm(field, value) {
    setQuickScoutReportMessage("");
    setQuickScoutReportForm((current) => {
      const next = { ...current, [field]: value };
      if (field === "dateMode") {
        if (value === "today") next.reportDate = getLocalDateKey();
        if (value === "yesterday") next.reportDate = getYesterdayDateKey();
      }
      if (field === "reportType") {
        const nextType = SCOUT_QUICK_REPORT_TYPES.find((option) => option.value === value);
        next.visibility = nextType?.isGuess ? normalizeScoutGuessVisibility(current.visibility || "private") : normalizeScoutReportVisibility(current.visibility || "public");
        if (nextType?.isGuess) next.dateMode = current.dateMode === "today" ? "day_only" : current.dateMode;
      }
      return next;
    });
  }

  function selectQuickScoutReportStore(store = {}) {
    setQuickScoutReportForm((current) => ({ ...current, ...buildQuickScoutStoreDraft(store) }));
  }

  function quickScoutReportTypeMeta(value = quickScoutReportForm.reportType) {
    return SCOUT_QUICK_REPORT_TYPES.find((option) => option.value === value) || SCOUT_QUICK_REPORT_TYPES[0];
  }

  function quickScoutStockLeftLabel(value = quickScoutReportForm.stockLeft) {
    const option = SCOUT_QUICK_STOCK_LEFT_OPTIONS.find((item) => item.value === value);
    return option ? option.label : "Not sure";
  }

  function quickScoutProofLabel(value = quickScoutReportForm.proofType) {
    const option = SCOUT_QUICK_PROOF_TYPES.find((item) => item.value === value);
    return option ? option.label : "Manual";
  }

  function quickScoutDateLabel(form = quickScoutReportForm) {
    if (form.dateMode === "not_sure") return "Not sure";
    if (form.dateMode === "day_only") return form.dayOfWeek || "Day not selected";
    const dateLabel = form.dateMode === "yesterday" ? getYesterdayDateKey() : form.reportDate || getLocalDateKey();
    return `${dateLabel}${form.reportTime ? ` at ${form.reportTime}` : ""}`;
  }

  function normalizeScoutReportVisibility(value = "") {
    const normalized = String(value || "").toLowerCase();
    if (["public", "public_cleaned", "community", "community_report"].includes(normalized)) return "public";
    if (["admin_only", "admin review only"].includes(normalized)) return "admin_only";
    return "private_from_map";
  }

  function normalizeScoutGuessVisibility(value = "") {
    const normalized = String(value || "").toLowerCase();
    if (["public", "public_cleaned", "community"].includes(normalized)) return "public";
    if (["shared", "shared_with_team", "team"].includes(normalized)) return "shared";
    return "private";
  }

  function scoutVisibilityOptionLabel(value = "", isGuess = false) {
    const options = isGuess ? SCOUT_GUESS_VISIBILITY_OPTIONS : SCOUT_REPORT_VISIBILITY_OPTIONS;
    return options.find((option) => option.value === value)?.label || value.replace(/_/g, " ");
  }

  function scoutConfidenceScore(value = "") {
    const normalized = String(value || "").toLowerCase();
    if (normalized === "confirmed") return 95;
    if (normalized === "likely") return 72;
    if (normalized === "possible") return 48;
    if (normalized === "rumor") return 30;
    if (normalized === "guess") return 22;
    return 40;
  }

  function quickScoutNormalizedReportType(type = quickScoutReportTypeMeta()) {
    if (type.value === "no_stock") return "no_stock";
    if (type.value === "line_queue_seen") return "line_seen";
    if (type.value === "restock_happening_now" || type.value === "stock_on_shelf" || type.value === "confirmed_purchase") return "restock";
    if (type.value === "truck_vendor_seen") return "vendor_seen";
    if (type.value === "online_stock_changed") return "online_drop";
    if (type.stockStatus === "low_stock") return "low_stock";
    return "other";
  }

  function quickScoutReportReady() {
    return Boolean(quickScoutReportForm.reportType && (quickScoutReportForm.storeId || quickScoutReportForm.manualLocation.trim() || quickScoutReportForm.storeName.trim()));
  }

  function buildQuickScoutReportRecord() {
    const type = quickScoutReportTypeMeta();
    const knownStore = quickScoutReportForm.storeId ? findScoutQuickStore({ id: quickScoutReportForm.storeId }) : null;
    const selectedStore = knownStore || quickScoutReportForm;
    const timestampSourceDate = quickScoutReportForm.dateMode === "yesterday"
      ? getYesterdayDateKey()
      : quickScoutReportForm.dateMode === "pick_date" || quickScoutReportForm.dateMode === "today"
        ? quickScoutReportForm.reportDate || getLocalDateKey()
        : getLocalDateKey();
    const reportedAt = new Date(`${timestampSourceDate}T${quickScoutReportForm.reportTime || getLocalTimeKey()}`).toISOString();
    const productName = quickScoutReportForm.productName.trim();
    const storeName = quickScoutReportForm.storeId
      ? getScoutQuickStoreName(selectedStore)
      : quickScoutReportForm.manualLocation.trim() || quickScoutReportForm.storeName || "Needs Store Review";
    const retailer = quickScoutReportForm.storeId
      ? getScoutQuickRetailer(selectedStore)
      : quickScoutReportForm.retailer || "Manual";
    const notes = [
      quickScoutReportForm.note.trim(),
      quickScoutReportForm.proofText.trim() ? `Proof/text: ${quickScoutReportForm.proofText.trim()}` : "",
      quickScoutReportForm.manualLocation.trim() && !quickScoutReportForm.storeId ? `Manual location: ${quickScoutReportForm.manualLocation.trim()}` : "",
      `Proof source: ${quickScoutProofLabel()}`,
      `Stock left: ${quickScoutStockLeftLabel()}`,
      quickScoutReportForm.dateMode === "day_only" ? `Day reported: ${quickScoutReportForm.dayOfWeek}` : "",
      quickScoutReportForm.dateMode === "not_sure" ? "Date/time not sure" : "",
    ].filter(Boolean).join(" | ");
    const id = makeId("quick-scout-report");
    return {
      id,
      reportId: id,
      reportType: type.reportType,
      quickReportType: type.value,
      quickReportLabel: type.label,
      stockStatus: type.stockStatus,
      sourceType: type.sourceType,
      source_type: type.sourceType,
      confidence: type.confidence,
      confidence_score: scoutConfidenceScore(type.confidence),
      storeId: quickScoutReportForm.storeId,
      store_id: quickScoutReportForm.storeId,
      storeName,
      store_name: storeName,
      retailer,
      chain: retailer,
      city: selectedStore.city || quickScoutReportForm.city || "",
      address: selectedStore.address || quickScoutReportForm.address || "",
      manualLocation: quickScoutReportForm.manualLocation.trim(),
      needsStoreReview: !quickScoutReportForm.storeId,
      needsReview: Boolean(type.needsReview || !quickScoutReportForm.storeId),
      verificationStatus: type.needsReview || !quickScoutReportForm.storeId ? "Needs Review" : "User Report",
      verification_status: type.needsReview || !quickScoutReportForm.storeId ? "pending" : "unverified",
      status: type.needsReview || !quickScoutReportForm.storeId ? "pending" : "unverified",
      verified: false,
      visibility: normalizeScoutReportVisibility(quickScoutReportForm.visibility),
      visibilitySelection: quickScoutReportForm.visibility,
      itemName: productName,
      productName,
      product_name: productName,
      productCategory: quickScoutReportForm.productCategory || "Pokemon",
      product_category: quickScoutReportForm.productCategory || "Pokemon",
      product_type: quickScoutReportForm.productCategory || "",
      set_name: "",
      quantitySeen: quickScoutReportForm.quantity,
      quantity_estimate: quickScoutReportForm.quantity,
      price: quickScoutReportForm.price,
      itemsSeen: productName ? [{
        productName,
        category: quickScoutReportForm.productCategory || "Pokemon",
        quantity: quickScoutReportForm.quantity,
        price: quickScoutReportForm.price,
        note: quickScoutReportForm.note.trim(),
      }] : [],
      reportText: notes || type.label,
      notes,
      photoUrls: quickScoutReportForm.photoUrl ? [quickScoutReportForm.photoUrl] : [],
      proofType: quickScoutReportForm.proofType,
      stockLeft: quickScoutReportForm.stockLeft,
      reportDate: timestampSourceDate,
      reportTime: quickScoutReportForm.reportTime,
      report_time: reportedAt,
      dayOfWeek: quickScoutReportForm.dayOfWeek,
      reportedAt,
      submittedAt: new Date().toISOString(),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      userId: currentUserProfile?.userId || currentUserProfile?.id || user?.id || "local-beta-scout",
      displayName: currentUserProfile?.displayName || user?.email || "Local Scout",
      sourceStatus: BETA_LOCAL_MODE ? "local_beta" : "local",
      report_type: quickScoutNormalizedReportType(type),
    };
  }

  function buildQuickScoutGuessRecord() {
    const knownStore = quickScoutReportForm.storeId ? findScoutQuickStore({ id: quickScoutReportForm.storeId }) : null;
    const selectedStore = knownStore || quickScoutReportForm;
    const storeName = quickScoutReportForm.storeId
      ? getScoutQuickStoreName(selectedStore)
      : quickScoutReportForm.manualLocation.trim() || quickScoutReportForm.storeName || "Needs Store Review";
    const guessedDay = quickScoutReportForm.dateMode === "day_only"
      ? quickScoutReportForm.dayOfWeek
      : quickScoutReportForm.dateMode === "not_sure"
        ? "Unknown"
        : new Date(`${quickScoutReportForm.reportDate || getLocalDateKey()}T00:00:00`).toLocaleDateString(undefined, { weekday: "long" });
    const id = makeId("store-guess");
    const now = new Date().toISOString();
    return {
      id,
      recordType: "guess",
      userId: currentUserProfile?.userId || currentUserProfile?.id || user?.id || "local-beta-scout",
      user_id: currentUserProfile?.userId || currentUserProfile?.id || user?.id || "local-beta-scout",
      displayName: currentUserProfile?.displayName || user?.email || "Local Scout",
      storeId: quickScoutReportForm.storeId,
      store_id: quickScoutReportForm.storeId,
      storeName,
      store_name: storeName,
      retailer: getScoutQuickRetailer(selectedStore),
      city: selectedStore.city || quickScoutReportForm.city || "",
      guessedDay,
      guessed_day: guessedDay,
      guessedTimeWindow: quickScoutReportForm.guessedTimeWindow || (quickScoutReportForm.reportTime ? `Around ${quickScoutReportForm.reportTime}` : ""),
      guessed_time_window: quickScoutReportForm.guessedTimeWindow || (quickScoutReportForm.reportTime ? `Around ${quickScoutReportForm.reportTime}` : ""),
      restockPatternNotes: quickScoutReportForm.note.trim() || quickScoutReportForm.proofText.trim() || "User pattern note; not confirmed stock.",
      restock_pattern_notes: quickScoutReportForm.note.trim() || quickScoutReportForm.proofText.trim() || "User pattern note; not confirmed stock.",
      productType: quickScoutReportForm.productName.trim(),
      product_type: quickScoutReportForm.productName.trim(),
      confidenceSelfRating: Number(quickScoutReportForm.confidenceSelfRating || 50),
      confidence_self_rating: Number(quickScoutReportForm.confidenceSelfRating || 50),
      confidence: "guess",
      sourceType: "manual_prediction",
      source_type: "manual_prediction",
      visibility: normalizeScoutGuessVisibility(quickScoutReportForm.visibility),
      createdAt: now,
      created_at: now,
      updatedAt: now,
      updated_at: now,
    };
  }

  function submitQuickScoutReport(event) {
    event?.preventDefault?.();
    if (guestPreviewActive) {
      setQuickScoutReportMessage("Create a free account to submit reports and build forecasts.");
      setVaultToast("Create a free account to submit reports and build forecasts.");
      return;
    }
    if (!quickScoutReportReady()) {
      setQuickScoutReportMessage("Choose a report type and a store or manual location.");
      return;
    }
    const currentType = quickScoutReportTypeMeta();
    const scoutData = getSharedScoutData();
    if (currentType.isGuess) {
      const guess = buildQuickScoutGuessRecord();
      const nextGuesses = [guess, ...(scoutData.storeGuesses || scoutSnapshot.storeGuesses || [])]
        .filter((entry, index, list) => list.findIndex((candidate) => String(candidate.id) === String(entry.id)) === index);
      saveSharedScoutData({ ...scoutData, storeGuesses: nextGuesses });
      setQuickScoutReportSaved(guess);
      setQuickScoutReportStep("submitted");
      setQuickScoutReportMessage("Guess saved to the planner. Forecasts will treat it as a guess, not confirmed stock.");
      setScoutView("guesses");
      setVaultToast("Guess saved to Scout Planner.");
      flowModalBaselineRef.current.scoutSubmit = quickScoutReportForm;
      return;
    }
    const report = buildQuickScoutReportRecord();
    const nextReports = [report, ...(scoutData.reports || scoutSnapshot.reports || [])]
      .filter((entry, index, list) => list.findIndex((candidate) => getScoutReportId(candidate) === getScoutReportId(entry)) === index);
    saveSharedScoutData({ ...scoutData, reports: nextReports });
    setQuickScoutReportSaved(report);
    setQuickScoutReportStep("submitted");
    setQuickScoutReportMessage("Report sent. You can add details now or later.");
    setScoutReportFilter("Latest");
    setScoutReportsPage(1);
    completeDailyAction("store", { badge: "restock_reporter", points: 10 });
    setVaultToast("Report sent. You can add details now or later.");
    flowModalBaselineRef.current.scoutSubmit = quickScoutReportForm;
  }

  function openQuickScoutReportDetails() {
    if (quickScoutReportSaved) setSelectedScoutReport(quickScoutReportSaved);
    closeFlowModal({ force: true, reset: true });
    setActiveTab("scout");
    setScoutView("reports");
  }

  function openScoutSubmitFlow(options = {}) {
    const seededStore = options.store || findScoutQuickStore(options);
    const seededReportType = SCOUT_QUICK_REPORT_TYPES.find((option) => option.value === options.reportType || option.reportType === options.reportType);
    const draft = createQuickScoutReportDraft({
      ...buildQuickScoutStoreDraft(seededStore || {}),
      reportType: seededReportType?.value || (options.action === "addGuess" ? "restock_guess" : "stock_on_shelf"),
      proofType: options.proofType || (options.action === "importIntel" ? "text_link" : "manual"),
      ...(options.action === "addGuess" ? { dateMode: "day_only", visibility: "private" } : {}),
      productName: options.productName || "",
      proofText: options.proofText || "",
      manualLocation: options.manualLocation || "",
    });
    setQuickScoutReportForm(draft);
    setQuickScoutReportStep("what");
    setQuickScoutReportMessage("");
    setQuickScoutReportSaved(null);
    flowModalBaselineRef.current.scoutSubmit = draft;
    setScoutSubTabTarget({
      tab: "reports",
      id: Date.now(),
      ...options,
    });
    openFlowModal("scoutSubmit", { size: "medium", source: options.source });
  }

  function openScoutGuessFlow() {
    openScoutSubmitFlow({ action: "addGuess", source: "scout-forecast" });
  }

  function openQuickAddAction(action) {
    setQuickAddMenuOpen(false);
    if (action === "tcgCommand") return openFlowModal("tcgCommandCenter", { size: "large", source: "quick-add" });
    if (action === "receipt") return openReceiptScanWorkflow();
    if (action === "multiDestination") return openProductAddFlow({ source: "quick-add" });
    if (action === "bulkAdd") return openBulkAddFlow("Mixed");
    if (action === "card") return openProductAddFlow({ source: "quick-add-card", seed: { productType: "Individual Card" }, destinations: { vault: true } });
    if (action === "sealed") return openProductAddFlow({ source: "quick-add-sealed", seed: { productType: "Sealed Product" }, destinations: { vault: true } });
    if (action === "vaultItem") return openProductAddFlow({ source: "quick-add-vault", destinations: { vault: true } });
    if (action === "searchVaultCatalog") return openVaultCatalogSearchFlow({ source: "quick-add" });
    if (action === "importCollection") return openVaultImportCollectionFlow();
    if (action === "quickFind" || action === "manualLookup" || action === "enterUpcSku") return openQuickFindFlow({ source: "quick-add" });
    if (action === "suggestCatalogItem") {
      return openMultiDestinationAddFlow({
        seed: {
          destinations: destinationDefaults({ tidetradr: true }),
          tidetradr: { ...BLANK_MULTI_DESTINATION_FORM.tidetradr, action: "suggest" },
        },
      });
    }
    if (action === "suggestCatalogCorrection") return openFeedbackDialog("catalog_data", { page: "TideTradr", topic: "Catalog correction" });
    if (action === "scanProduct") return beginScanProduct("none");
    if (action === "pictureLookup") return openPictureLookupFlow("none");
    if (action === "scanVault") return openVaultScanFlow();
    if (action === "scanForge") {
      return beginScanProduct("none");
    }
    if (action === "pictureLookupVault") return openPictureLookupFlow("none");
    if (action === "pictureLookupForge") return openPictureLookupFlow("none");
    if (action === "inventory") return openProductAddFlow({ source: "quick-add-forge-inventory", destinations: { forge: true } });
    if (action === "sale") return openAddSaleFlow();
    if (action === "expense") return openAddExpenseFlow();
    if (action === "mileage") return openAddMileageFlow();
    if (action === "listing") return openMarketplaceCreate("manual", {});
    if (action === "importFile") return openForgeImportFlow();
    if (action === "storeReport") {
      return openScoutSubmitFlow({ source: "add-action-sheet" });
    }
    if (action === "store" || action === "storeSuggestion") {
      setScoutSubTabTarget({ tab: "stores", action: "missingStore", id: Date.now() });
      setScoutView("stores");
      setActiveTab("scout");
      return;
    }
    if (action === "storeCorrection") {
      return openScoutSubmitFlow({ action: "storeCorrection" });
    }
    if (action === "wishlist") {
      return openMultiDestinationAddFlow({
        source: "quick-add-wishlist",
        seed: {
          destinations: destinationDefaults({ wishlist: true }),
          wishlist: { ...BLANK_MULTI_DESTINATION_FORM.wishlist, addToMarketWatch: true },
        },
      });
    }
    if (action === "searchTidetradr") {
      setActiveTab("market");
      setTideTradrSubTab("overview");
      return;
    }
    if (action === "checkDeal") {
      setActiveTab("market");
      openDealFinderModal();
      return;
    }
    if (action === "whatDidISee") return openWhatDidISee();
    if (action === "listing") return openMarketplaceCreate("manual", {});
    return null;
  }

  function runQuickFindSearch(event, mode = "general") {
    event?.preventDefault?.();
    const lookup = String(quickFindForm.lookup || "").trim();
    setActiveTab("market");
    setTideTradrSubTab("overview");
    if (!lookup) {
      closeFlowModal({ force: true, reset: false });
      setQuickFindForm(BLANK_QUICK_FIND_FORM);
      return;
    }
    setCatalogSearch(lookup);
    setCatalogSearchHasRun(true);
    closeCatalogSuggestions();
    if (mode === "barcode") {
      setCatalogBarcodeSearch(lookup);
      setSubmittedCatalogSearch(lookup);
      setSubmittedCatalogBarcodeSearch(lookup);
      loadImportedPokemonCatalog(lookup, { page: 1, mode: "barcode", barcode: lookup });
    } else {
      setCatalogBarcodeSearch("");
      setSubmittedCatalogSearch(lookup);
      setSubmittedCatalogBarcodeSearch("");
      loadImportedPokemonCatalog(lookup, { page: 1, mode: "general", barcode: "" });
    }
    closeFlowModal({ force: true, reset: false });
    setQuickFindForm(BLANK_QUICK_FIND_FORM);
  }

  function runVaultCatalogSearch(event, value = vaultCatalogSearchQuery) {
    event?.preventDefault?.();
    const lookup = String(value || "").trim();
    setVaultCatalogSearchQuery(lookup);
    if (!lookup) return;
    setCatalogSearch(lookup);
    setCatalogBarcodeSearch("");
    setSubmittedCatalogSearch(lookup);
    setSubmittedCatalogBarcodeSearch("");
    setCatalogSearchHasRun(true);
    closeCatalogSuggestions();
    loadImportedPokemonCatalog(lookup, {
      page: 1,
      pageSize: Math.min(24, catalogPageSize || 24),
      mode: "general",
      barcode: "",
      forceSearch: true,
    });
  }

  function selectVaultCatalogSearchProduct(product) {
    openMultiDestinationAddForProduct(product, {
      source: "vault-catalog",
      seed: {
        destinations: { vault: false, wishlist: false, forge: false, tidetradr: false },
      },
    });
  }

  function selectVaultCatalogSearchSuggestion(suggestion) {
    const value = suggestion.searchValue || suggestion.label || vaultCatalogSearchQuery;
    setVaultCatalogSearchQuery(value);
    if (suggestion.product?.id) {
      selectVaultCatalogSearchProduct(suggestion.product);
      return;
    }
    runVaultCatalogSearch(null, value);
  }

  function selectMultiDestinationCatalogSuggestion(suggestion) {
    const value = suggestion.searchValue || suggestion.label || multiDestinationCatalogQuery;
    setMultiDestinationCatalogQuery(value);
    if (suggestion.product?.id) {
      selectMultiDestinationCatalogProduct(suggestion.product);
      return;
    }
    loadImportedPokemonCatalog(value, {
      page: 1,
      pageSize: Math.min(24, catalogPageSize || 24),
      mode: "general",
      barcode: "",
      forceSearch: true,
    });
  }

  async function submitMultiDestinationAdd(event) {
    event.preventDefault();
    if (multiDestinationSaving) return;
    if (blockGuestSave()) return;
    const itemName = String(multiDestinationForm.itemName || "").trim();
    const destinations = multiDestinationForm.destinations || {};
    const selectedDestinationCount = Object.values(destinations).filter(Boolean).length;
    if (!itemName) {
      setMultiDestinationMessage("Enter an item name before adding.");
      return;
    }
    if (!selectedDestinationCount) {
      setMultiDestinationMessage("Choose Add to Vault, Add to Forge, Wishlist, or TideTradr before adding.");
      return;
    }

    setMultiDestinationSaving(true);
    setMultiDestinationMessage("Saving item...");
    const now = new Date().toISOString();
    const selectedCatalog = catalogProducts.find((product) => String(product.id) === String(multiDestinationForm.catalogProductId));
    const successes = [];
    const failures = [];
    const pendingInventoryCreates = [];
    const destinationWorkspace = (destination) => {
      const workspaceId = multiDestinationForm[destination]?.workspaceId || defaultWorkspaceIdForDestination(destination);
      return workspaces.find((workspace) => String(workspace.id) === String(workspaceId)) || activeWorkspace;
    };
    const canWriteDestination = (destination) => {
      const workspace = destinationWorkspace(destination);
      return canEditWorkspaceId(workspace?.id);
    };
    const shared = {
      name: itemName,
      category: multiDestinationForm.category || "Pokemon",
      productType: normalizedInventoryProductType({
        ...selectedCatalog,
        name: itemName,
        productType: multiDestinationForm.productType || selectedCatalog?.productType || "",
        setName: multiDestinationForm.setName || selectedCatalog?.setName || selectedCatalog?.expansion || "",
      }),
      barcode: multiDestinationForm.upcSku || "",
      catalogProductId: selectedCatalog?.id || "",
      catalogVariantId: multiDestinationForm.catalogVariantId || "",
      catalogProductName: selectedCatalog?.name || "",
      marketPrice: Number(multiDestinationForm.marketPrice || selectedCatalog?.marketPrice || selectedCatalog?.midPrice || 0),
      msrpPrice: Number(multiDestinationForm.msrpPrice || selectedCatalog?.msrpPrice || 0),
      setName: multiDestinationForm.setName || (selectedCatalog ? catalogExpansionName(selectedCatalog) : multiDestinationForm.tidetradr.setName),
      expansion: multiDestinationForm.setName || (selectedCatalog ? catalogExpansionName(selectedCatalog) : multiDestinationForm.tidetradr.setName),
      variant: multiDestinationForm.variant || "",
      notes: multiDestinationForm.notes || "",
      sourceType: selectedCatalog ? "TideTradr" : "Multi-destination add",
    };

    try {
      if (destinations.vault) {
        if (!canWriteDestination("vault")) throw new Error("You do not have permission to edit this workspace.");
        const vaultQuantity = Math.max(1, Number(multiDestinationForm.vault.quantity || 1));
        const vaultWorkspace = destinationWorkspace("vault");
        const vaultItem = applyWorkspaceToRecord({
          id: makeId("vault"),
          ...shared,
          destinationScope: ["vault"],
          recordType: "vault_item",
          businessInventory: false,
          isWishlist: false,
          quantity: vaultQuantity,
          ownedQuantity: vaultQuantity,
          forgeQuantity: 0,
          unitCost: Number(multiDestinationForm.vault.unitCost || 0),
          status: vaultStatusLabel(multiDestinationForm.vault.vaultStatus),
          vaultStatus: multiDestinationForm.vault.vaultStatus,
          vaultCategory: multiDestinationForm.vault.vaultCategory,
          purchaseDate: multiDestinationForm.vault.purchaseDate,
          storageLocation: multiDestinationForm.vault.storageLocation || vaultStatusLabel(multiDestinationForm.vault.vaultStatus),
          actionNotes: [multiDestinationForm.vault.notes, multiDestinationForm.notes].filter(Boolean).join(" "),
          conditionName: "Near Mint",
          language: "English",
          createdAt: now,
        }, vaultWorkspace);
        pendingInventoryCreates.push({ record: vaultItem, successMessage: `Added to Vault (${vaultWorkspace?.name || "Workspace"})` });
      }
    } catch (error) {
      failures.push(`Vault failed: ${error.message || "Could not save"}`);
    }

    try {
      if (destinations.wishlist) {
        if (!canWriteDestination("wishlist")) throw new Error("You do not have permission to edit this workspace.");
        const wishlistQuantity = Math.max(1, Number(multiDestinationForm.wishlist.quantity || 1));
        const wishlistWorkspace = destinationWorkspace("wishlist");
        const wishlistItem = applyWorkspaceToRecord({
          id: makeId("wishlist"),
          ...shared,
          destinationScope: ["wishlist"],
          recordType: "wishlist_item",
          businessInventory: false,
          isWishlist: true,
          quantity: wishlistQuantity,
          quantityWanted: wishlistQuantity,
          ownedQuantity: 0,
          unitCost: 0,
          targetPrice: Number(multiDestinationForm.wishlist.targetPrice || 0),
          status: "Wishlist",
          vaultStatus: "wishlist",
          vaultCategory: "Wishlist",
          storageLocation: "Wishlist",
          wishlistPriority: multiDestinationForm.wishlist.priority,
          desiredCondition: multiDestinationForm.wishlist.desiredCondition,
          wishlistNotes: multiDestinationForm.wishlist.notes,
          alertMarketPrice: Boolean(multiDestinationForm.wishlist.alertMarketPrice),
          addToMarketWatch: Boolean(multiDestinationForm.wishlist.addToMarketWatch),
          actionNotes: [
            "Wishlist item - wanted, not owned.",
            multiDestinationForm.wishlist.notes,
            multiDestinationForm.notes,
          ].filter(Boolean).join(" "),
          conditionName: multiDestinationForm.wishlist.desiredCondition || "Any",
          language: "English",
          createdAt: now,
        }, wishlistWorkspace);
        pendingInventoryCreates.push({ record: wishlistItem, successMessage: `Added to Wishlist (${wishlistWorkspace?.name || "Workspace"})` });

        if (multiDestinationForm.wishlist.addToMarketWatch && selectedCatalog?.id) {
          addProductToTideTradrWatchlist(selectedCatalog.id, false, wishlistWorkspace?.id);
          successes.push("Added to Watchlist");
        }
      }
    } catch (error) {
      failures.push(`Wishlist failed: ${error.message || "Could not save"}`);
    }

    try {
      if (destinations.forge) {
        if (!canWriteDestination("forge")) throw new Error("You do not have permission to edit this workspace.");
        const forgeQuantity = Math.max(1, Number(multiDestinationForm.forge.quantity || 1));
        const forgeWorkspace = destinationWorkspace("forge");
        const forgeItem = applyWorkspaceToRecord({
          id: makeId("item"),
          ...shared,
          destinationScope: ["forge"],
          recordType: "forge_inventory",
          businessInventory: true,
          quantity: forgeQuantity,
          forgeQuantity,
          ownedQuantity: 0,
          unitCost: Number(multiDestinationForm.forge.unitCost || 0),
          salePrice: Number(multiDestinationForm.forge.plannedSellPrice || 0),
          category: multiDestinationForm.forge.businessCategory || shared.category,
          store: multiDestinationForm.forge.source || "",
          status: "In Stock",
          buyer: "Zena",
          purchaserId: "purchaser-default-1",
          purchaserName: "Zena",
          conditionName: multiDestinationForm.forge.conditionName || "Near Mint",
          language: "English",
          notes: [multiDestinationForm.forge.notes, multiDestinationForm.notes].filter(Boolean).join(" "),
          createdAt: now,
        }, forgeWorkspace);
        pendingInventoryCreates.push({ record: forgeItem, successMessage: `Added to Forge inventory (${forgeWorkspace?.name || "Workspace"})` });
      }
    } catch (error) {
      failures.push(`Forge failed: ${error.message || "Could not save"}`);
    }

    try {
      if (destinations.tidetradr) {
        const existingProductId = multiDestinationForm.tidetradr.existingProductId || selectedCatalog?.id || "";
        if (existingProductId) {
          addProductToTideTradrWatchlist(existingProductId, false, activeWorkspace?.id);
          successes.push("Added to Watchlist");
        } else if (adminToolsVisible) {
          const catalogProduct = {
            id: makeId("catalog"),
            name: itemName,
            productName: itemName,
            category: multiDestinationForm.category || "Pokemon",
            productType: multiDestinationForm.tidetradr.productType || multiDestinationForm.productType,
            setName: multiDestinationForm.tidetradr.setName || shared.setName,
            expansion: multiDestinationForm.tidetradr.setName || shared.setName,
            barcode: multiDestinationForm.tidetradr.upc || multiDestinationForm.upcSku,
            sku: multiDestinationForm.tidetradr.sku,
            msrpPrice: Number(multiDestinationForm.tidetradr.msrpPrice || multiDestinationForm.msrpPrice || 0),
            marketPrice: Number(multiDestinationForm.marketPrice || 0),
            releaseDate: multiDestinationForm.tidetradr.releaseDate,
            sourceUrl: multiDestinationForm.tidetradr.sourceUrl,
            notes: [multiDestinationForm.tidetradr.correctionNotes, multiDestinationForm.notes].filter(Boolean).join(" "),
            workspaceId: activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
            workspaceName: activeWorkspace?.name || "My Personal Space",
            sourceType: "admin_created",
            marketStatus: "Manual",
            createdAt: now,
          };
          setCatalogProducts((current) => [catalogProduct, ...current]);
          setTideTradrWatchlist((current) => [
            applyWorkspaceToRecord({
              id: makeId("watch"),
              productId: catalogProduct.id,
              name: catalogProduct.name,
              setName: catalogProduct.setName,
              productType: catalogProduct.productType,
              marketValue: Number(catalogProduct.marketPrice || 0),
              msrp: Number(catalogProduct.msrpPrice || 0),
              sourceName: "Admin",
              pinned: false,
              lastUpdated: now,
            }, activeWorkspace),
            ...current,
          ]);
          successes.push("Created TideTradr catalog item");
        } else {
          submitUniversalSuggestion({
            suggestionType: SUGGESTION_TYPES.ADD_MISSING_CATALOG_PRODUCT,
            targetTable: "product_catalog",
            submittedData: {
              name: itemName,
              category: multiDestinationForm.category,
              productType: multiDestinationForm.tidetradr.productType || multiDestinationForm.productType,
              setName: multiDestinationForm.tidetradr.setName || shared.setName,
              releaseDate: multiDestinationForm.tidetradr.releaseDate,
              msrpPrice: multiDestinationForm.tidetradr.msrpPrice || multiDestinationForm.msrpPrice,
              upc: multiDestinationForm.tidetradr.upc || multiDestinationForm.upcSku,
              sku: multiDestinationForm.tidetradr.sku,
              sourceUrl: multiDestinationForm.tidetradr.sourceUrl,
              notes: [multiDestinationForm.tidetradr.correctionNotes, multiDestinationForm.notes].filter(Boolean).join(" "),
              workspaceId: activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
              workspaceName: activeWorkspace?.name || "My Personal Space",
            },
            currentDataSnapshot: {},
            proofUrl: multiDestinationForm.tidetradr.sourceUrl,
            notes: [multiDestinationForm.tidetradr.correctionNotes, multiDestinationForm.notes].filter(Boolean).join(" "),
            source: "user",
          });
          successes.push("Submitted TideTradr suggestion");
        }
      }
    } catch (error) {
      failures.push(`TideTradr failed: ${error.message || "Could not save"}`);
    }

    if (pendingInventoryCreates.length) {
      const saveResult = await saveInventoryRecords(pendingInventoryCreates.map((entry) => entry.record));
      const savedInventoryItems = saveResult.saved || [];
      if (savedInventoryItems.length) {
        setItems((current) => [...savedInventoryItems, ...current]);
        if (savedInventoryItems.length === pendingInventoryCreates.length) {
          successes.push(...pendingInventoryCreates.map((entry) => entry.successMessage));
        } else {
          successes.push(`Saved ${savedInventoryItems.length} destination item${savedInventoryItems.length === 1 ? "" : "s"}.`);
        }
      }
      if (saveResult.failures?.length) {
        failures.push(...saveResult.failures.map((failure) => `${failure.itemName || "Inventory item"} failed: ${failure.error || "Could not save"}`));
      }
    }

    const uniqueSuccesses = [...new Set(successes)];
    const uniqueFailures = [...new Set(failures)];
    if (uniqueFailures.length) console.error("Multi-destination save failures", uniqueFailures);
    if (uniqueSuccesses.length) setVaultToast(uniqueFailures.length ? `${uniqueSuccesses.join(" | ")}. Could not save item.` : uniqueSuccesses.join(" | "));
    if (!successes.length && uniqueFailures.length) setVaultToast("Could not save item.");
    if (failures.length) {
      setMultiDestinationMessage("Could not save item. Check the destination details and try again.");
      setMultiDestinationSaving(false);
      return;
    }
    setMultiDestinationSaving(false);
    closeFlowModal({ force: true, reset: false });
    resetMultiDestinationForm();
  }

