  function mapExpense(row) {
    const normalizedCategory =
      row.category === "Gas"
        ? "Mileage/Vehicle"
        : row.category === "Software"
          ? "Software/Subscriptions"
          : row.category === "Other"
            ? "Miscellaneous"
            : ["Storage", "Equipment"].includes(row.category)
              ? "Supplies"
              : row.category || "Supplies";
    return {
      id: row.id,
      expenseId: row.id,
      date: row.date || row.expense_date || "",
      vendor: row.vendor || "",
      category: normalizedCategory,
      subcategory: row.subcategory || "",
      buyer: row.buyer || "Zena",
      amount: Number(row.amount || 0),
      paymentMethod: row.paymentMethod || row.payment_method || "",
      linkedItemId: row.linkedItemId || row.linked_item_id || "",
      linkedSaleId: row.linkedSaleId || row.linked_sale_id || "",
      notes: row.notes || "",
      receiptImage: row.receiptImage || row.receipt_image || row.receipt_photo || "",
      receiptPhoto: row.receiptPhoto || row.receipt_photo || row.receipt_image || "",
      rawReceiptText: row.rawReceiptText || row.raw_receipt_text || row.raw_ocr_text || "",
      receiptSplitMode: row.receiptSplitMode || row.receipt_split_mode || "expense_only",
      receiptTax: row.receiptTax || row.receipt_tax || "",
      receiptPersonalTotal: row.receiptPersonalTotal || row.receipt_personal_total || "",
      taxDeductible: !!(row.taxDeductible || row.tax_deductible),
      campaignName: row.campaignName || row.campaign_name || "",
      platform: row.platform || "",
      goal: row.goal || "",
      startDate: row.startDate || row.start_date || "",
      endDate: row.endDate || row.end_date || "",
      linkedSales: row.linkedSales || row.linked_sales || "",
      resultsNotes: row.resultsNotes || row.results_notes || "",
      workspaceId: row.workspaceId || row.workspace_id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspace_id: row.workspace_id || row.workspaceId || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspaceName: row.workspaceName || row.workspace_name || "",
      createdAt: row.createdAt || row.created_at,
      updatedAt: row.updatedAt || row.updated_at,
    };
  }

